{
 "serverInfo": {
 "name": "com.webflow/mcp",
 "title": "Webflow MCP Server",
 "version": "2.0.0"
 },
 "description": "AI-powered design and management for Webflow Sites. Connect your AI tools to manage CMS content, design pages, publish sites, and work with components through natural language.",
 "iconUrl": "https://webflow.com/favicon.ico",
 "documentationUrl": "https://developers.webflow.com/mcp/reference/overview",
 "transport": {
 "type": "streamable-http",
 "endpoint": "https://mcp.webflow.com/mcp"
 },
 "capabilities": {
 "tools": { "listChanged": true },
 "resources": { "listChanged": true },
 "prompts": {}
 },
 "authentication": {
 "required": true,
 "schemes": ["oauth2"]
 },
 "instructions": "Call webflow_guide_tool once to learn available Webflow MCP capabilities before using any other tools. Only call it once per session.",
 "tools": [
 {
 "name": "data_sites_tool",
 "title": "Data Sites Tool",
 "description": "Data tool - Sites tool to perform actions like list sites, get site details, and publish sites",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "data_pages_tool",
 "title": "Data Pages Tool",
 "description": "Data tool - Pages tool to perform actions like list pages, get page metadata, update page settings, get page content, and update static content",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "data_cms_tool",
 "title": "Data CMS Tool",
 "description": "Data tool - CMS tool to perform actions like get collection list, get collection details, create collection, create collection fields (static/option/reference), update collection field, delete collection field, list collection items, create collection items, update collection items, publish collection items, delete collection items, and unpublish collection items",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "data_components_tool",
 "title": "Data Components Tool",
 "description": "Data tool - Components tool to perform actions like list components, get component content, update component content, get component properties, and update component properties",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "data_enterprise_tool",
 "title": "Data Enterprise Tool",
 "description": "Data tool - Enterprise tool to perform actions like manage 301 redirects, manage robots.txt and more. This tool only works if User's workspace plan is Enterprise or higher, else tool will return an error.",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "data_webhook_tool",
 "title": "Data Webhook Tool",
 "description": "Data tool - Webhook tool to perform actions like list webhooks, create webhooks, get webhook details, and delete webhooks for a Webflow site.",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "data_comments_tool",
 "title": "Data Comments Tool",
 "description": "Data tool - A comment in Webflow is user feedback attached to a specific element or page inside the Designer, stored as a top-level thread with optional replies. Each comment includes author info, timestamps, content, resolved state, and design-context metadata like page location and breakpoint. Use this tool to inspect feedback discussions, filter threads by page, resolution status, or creation date, search for comment users by email, and create replies to existing threads.",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "data_scripts_tool",
 "title": "Data Scripts Tool",
 "description": "Data tool - Scripts tool to manage custom code scripts. Register, apply, update, and remove scripts at the site or page level.",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "data_workflows_tool",
 "title": "Data Workflows Tool",
 "description": "Data tool - Workflows tool to list AI workflows, run a workflow, list workflow runs, and get a workflow run.",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "data_sitemap_tool",
 "title": "Data Sitemap Indexing Tool",
 "description": "Data tool - Manage sitemap indexing status for CMS collection items and static pages. Read and update whether pages and collection items appear in a site's generated sitemap. All endpoints are under the /beta namespace. Folder pages, collection template pages, and utility pages are not supported for page endpoints.",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "data_assets_tool",
 "title": "Data Assets Tool",
 "description": "Data tool - Manage Webflow site assets via the Data API. Generates asset metadata entries and returns presigned S3 upload information (uploadUrl and uploadDetails) used to upload the file bytes.",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "data_style_tool",
 "title": "Style Tool",
 "description": "Data Tool - Style tool to perform actions like get all styles, create a new style, update a style, query styles, and remove a style",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "asset_tool",
 "title": "Designer Asset Tool",
 "description": "Designer Tool - Asset tool to perform actions like create folder, get all assets and folders, update assets and folders",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "de_component_tool",
 "title": "Designer Component Tool",
 "description": "Designer tool - Component tool to perform actions like create component instances, get all components and more.",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "element_tool",
 "title": "Designer Element Tool",
 "description": "Designer Tool - Element tool to perform actions like get all elements, get selected element, select element on current active page. and more",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "de_page_tool",
 "title": "Designer Page Tool",
 "description": "Designer Tool - Page tool to perform actions like create page, create page folder, get current page, switch page",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "variable_tool",
 "title": "Designer Variable Tool",
 "description": "Designer Tool - Variable tool to perform actions like create variable, get all variables, update variable",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "ask_webflow_ai",
 "title": "Ask Webflow AI",
 "description": "Ask Webflow AI about anything related to Webflow API.",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "webflow_guide_tool",
 "title": "Webflow Guide Tool",
 "description": "Provides essential guidelines and best practices for effectively using the Webflow tools. Call this tool to understand recommended workflows and important considerations before performing actions. ALWAYS CALL THIS TOOL FIRST BEFORE CALLING ANY OTHER TOOLS. ALWAYS CALL THIS TOOL FIRST BEFORE CALLING ANY OTHER TOOLS. ",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "get_image_preview",
 "title": "Get Webflow Image Preview",
 "description": "Designer Tool - Get image preview from url. this is helpful to get image preview from url. Only supports JPG, PNG, GIF, WEBP, WEBP and AVIF formats.",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "component_builder",
 "title": "Component Builder",
 "description": "Designer Tool - Component builder to insert component instances on the current active page. Supports inserting into an element (as a child) or into a component instance's slot. Use insert_in_element to add a component inside a container/div/section. Use insert_in_slot to add a component inside a specific slot of an existing component instance.",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "element_builder",
 "title": "Element Builder",
 "description": "Designer Tool - Element builder to create element on current active page.",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "whtml_builder",
 "title": "WHTML Builder",
 "description": "Designer Tool - WHTML builder to insert elements from HTML and CSS strings on the current active page. Accepts HTML markup and optional CSS rules, constructs WHTML, and inserts into a parent element.",
 "inputSchema": { "type": "object" }
 },
 {
 "name": "element_snapshot_tool",
 "title": "Element Snapshot Tool",
 "description": "Designer Tool - Element snapshot tool to perform actions like get element snapshot. helpful to get element snapshot for debugging and more and visual feedback.",
 "inputSchema": { "type": "object" }
 }
 ],
 "resources": [
 {
 "name": "webflow_asset_upload_guide",
 "title": "Webflow Asset Upload Guide",
 "uri": "webflow://guides/asset-upload",
 "description": "How to upload the actual file bytes to Amazon S3 after calling data_assets_tool > create_asset. Includes Node, Python, and curl examples.",
 "mimeType": "text/markdown"
 },
 {
 "name": "webflow_cloud_guide",
 "title": "Webflow Cloud Guide",
 "uri": "webflow://guides/cloud",
 "description": "Webflow Cloud setup and deployment guide. Read this resource when the user wants to create a new Webflow Cloud app or deploy a project for the first time. Returns step-by-step instructions for CLI setup, project initialization, and first deploy. Also covers how future deployments can be triggered via GitHub or MCP tools.",
 "mimeType": "text/markdown"
 },
 {
 "name": "webflow_guide",
 "title": "Webflow Guide",
 "uri": "webflow://guides/mcp-guide",
 "description": "MCP guidelines and best practices for effectively using the Webflow MCP tools. Same content as the webflow_guide_tool, exposed as a resource so clients can prefetch and pin it in context without making a tool call.",
 "mimeType": "text/markdown"
 }
 ],
 "prompts": [],
 "provider": {
 "name": "Webflow, Inc.",
 "url": "https://webflow.com"
 }
}
